const d = $input.first().json;
const subgroupEnvMap = {
  tech:       $env.WA_GROUP_TECH_INVITE,
  marketing:  $env.WA_GROUP_MARKETING_INVITE,
  ecommerce:  $env.WA_GROUP_ECOMMERCE_INVITE,
  media:      $env.WA_GROUP_MEDIA_INVITE,
  agency:     $env.WA_GROUP_AGENCY_INVITE,
  finance:    $env.WA_GROUP_FINANCE_INVITE,
};
const subgroupNameMap = {
  tech:       'EOA CM – Tech & SaaS',
  marketing:  'EOA CM – Marketing & Growth',
  ecommerce:  'EOA CM – E-commerce',
  media:      'EOA CM – Media & Content',
  agency:     'EOA CM – Agency & Services',
  finance:    'EOA CM – Investors & Finance',
};

// Build HTML list of subgroup invites for Day 1 email
const matched = (d.matchedSubgroups || []);
let subgroupHtml = '';
if (matched.length > 0) {
  const items = matched
    .filter(g => subgroupEnvMap[g.key])
    .map(g => `<li><a href="${subgroupEnvMap[g.key]}">${subgroupNameMap[g.key]}</a></li>`)
    .join('');
  if (items) {
    subgroupHtml = `<p><strong>Based on your niche (${d.businessNiche}), we also recommend joining:</strong></p><ul>${items}</ul>`;
  }
}

return [{ json: { ...d, subgroupHtml } }];
